      { q: "Sezen Aksu'nun 'Sarı Saçlım Mavi Gözlüm' şarkısını kime yazdığı söylenir?", o: ["Ajda Pekkan'a (1976)", "Zeki Müren'e", "Barış Manço'ya", "Tarkan'a"], a: 0, e: "Sezen Aksu bu şarkıyla kariyer başlangıcında Türk pop tarihinde iz bıraktı." },
      { q: "Hangi ülkenin geleneksel müziği 'Flamenco' adıyla bilinir?", o: ["İspanya (Endülüs bölgesi)", "Portekiz", "İtalya", "Arjantin"], a: 0, e: "Flamenko UNESCO Dünya Mirası'nda; gitar, şarkı (cante) ve dans (baile) üçlüsünden oluşur." },
      { q: "Türk müziğinde 'segah' makamı ne tür bir his uyandırır?", o: ["Hüzün, içe çekilme ve dini coşku", "Neşe ve canlılık", "Gurbet ve özlem", "Kararlılık ve güç"], a: 0, e: "Segah makamı tekke müziğinde ve dini eserlerde çok kullanılır; özellikle ruhanî bir derinlik taşır." },
      { q: "Dünyaca ünlü 'Barselona' şarkısı Freddie Mercury ile kimi için söylemiştir?", o: ["Soprano Montserrat Caballé ile (1987)", "Michael Jackson ile", "Elton John ile", "David Bowie ile"], a: 0, e: "Queen'in söz yazarı Mercury bu düeti Katalonya operası yıldızı Caballé ile 1992 Olimpiyatları teması olarak seslendirdi." },
      { q: "Türkiye'nin Eurovision 2003 şarkısının adı nedir?", o: ["Every Way That I Can", "Fly to Stay Alive", "Always", "Live Is Easy"], a: 0, e: "Sertab Erener'in Rıza Pars yazarlığındaki bu şarkı Türkiye'ye tek Eurovision birinciliğini kazandırdı." },
      { q: "Hangisi bir 'perküsyon' enstrümanı değildir?", o: ["Akordeon", "Davul", "Maraka", "Zil"], a: 0, e: "Akordeon körüğe basarak hava üflenen reedli bir nefesli çalgıdır; perküsyon değildir." },
      { q: "Türk pop müziğinin 'Kraliçesi' olarak anılan sanatçı kimdir?", o: ["Ajda Pekkan", "Sezen Aksu", "Nilüfer", "Çiğdem Talu"], a: 0, e: "Ajda Pekkan 1960'lardan bu yana Türk pop sahnesinin tartışmasız süperstarı olarak anılmaktadır." },
      { q: "Bir 'gitar perde' (fret) ne işe yarar?", o: ["Telin belirli bir noktada basılmasını sağlayarak nota yüksekliğini belirler", "Teli gevşetir", "Akort vidasını tutar", "Ses deliği olarak işlev görür"], a: 0, e: "Her perde yarım ses (yarım ton) aralığına denk gelir; 12 perde bir oktav oluşturur." },
      { q: "'Dueling Banjos' hangi filmde yer alır?", o: ["Deliverance (Kurtarış, 1972)", "Forrest Gump", "O Brother, Where Art Thou?", "Coal Miner's Daughter"], a: 0, e: "Bu ikonik banjo düeti John Boorman'ın gerilim filminin açılışında yer alır; Arthur Smith'in aynı adlı parçasından uyarlanmıştır." },
      { q: "Türkiye'nin en uzun süre yayın yapan radyo kanalı hangisidir?", o: ["TRT Radyo 1 (1927'de kurulan devlet radyosu)", "Radyo 35", "Power FM", "Radyo Viva"], a: 0, e: "Türk radyoculuğu Ankara Radyosu ile 1927'de başladı; daha sonra TRT bünyesine girdi." },
      { q: "Hangi müzik terimi Türkçe'ye 'ağır ve tökezleyerek' olarak çevrilebilir?", o: ["Andante (yürüyüş hızında)", "Grave (çok ağır, ciddi)", "Largo", "Adagio"], a: 1, e: "Grave en yavaş tempolardan biridir; İtalyanca 'ağır, ciddi' anlamına gelir." },
      { q: "Türkiye'nin kendi özel müzik ödülü töreni nedir?", o: ["Altın Kelebek Müzik Ödülleri", "TRT Müzik Ödülleri", "Grammy Türkiye", "Panteon Ödülleri"], a: 0, e: "Altın Kelebek ödülleri pop müzikten arabeske geniş yelpazede Türk müzisyenleri onurlandırır." }
