      { q: "DNS önbellek zehirlenmesi (DNS cache poisoning) nasıl gerçekleşir?", o: ["Sahte DNS yanıtları enjekte ederek kullanıcıyı yanlış IP adresine yönlendirme", "DNS sunucusunu DDoS ile çökertme", "DNS kayıt silme saldırısı", "SSL sertifikasını geçersiz kılma"], a: 0, e: "Kaminsky saldırısı 2008'de bu açığı büyük çaplı ortaya koydu; DNSSEC bu sorunu dijital imzayla çözer." },
      { q: "Fiziksel güvenlikte 'rubber hose cryptanalysis' ne anlama gelir?", o: ["Şifrelenmiş veriyi çözmek için teknik yöntem yerine kişiyi zorlama/tehdit etme", "Güç analizi saldırısı", "Yan kanal şifre kırma", "Şifrelenmiş trafiği analiz etme"], a: 0, e: "Anahtar teslimi yasaları bazı ülkelerde bu yöntemi yasal kılmaktadır; matematik yerine insan zafiyetini hedef alır." },
      { q: "Ethereum'un 'Proof of Stake'e' geçişinin (The Merge, 2022) teknik önemi nedir?", o: ["Enerji tüketimini %99.95 azalttı; madencilik yerine doğrulayıcı stake mekanizması", "İşlem hızını 1000x artırdı", "Akıllı sözleşmeleri mümkün kıldı", "Ethereum 2.0 tamamen yeni bir blockchain kurdu"], a: 0, e: "Proof of Work'ün karbon ayak izine karşı önemli bir adım; ama ölçeklenebilirlik (sharding) hâlâ tamamlanmadı." },
      { q: "Tersine mühendislik (reverse engineering) bağlamında 'decompilation' ve 'disassembly' arasındaki fark nedir?", o: ["Disassembly makine kodunu assembly'e; decompilation binary'i yüksek seviyeli koda dönüştürür", "İkisi de aynı işlemi yapar", "Decompilation kaynak kodunu binary'e çevirir", "Disassembly yalnızca Windows için çalışır"], a: 0, e: "Ghidra ve IDA Pro; Jadx ve CFR sırasıyla en bilinen araçlardır; kötü amaçlı yazılım analizi ve hata araştırmasında kullanılır." },
      { q: "Donanımda 'side-channel attack' (yan kanal saldırısı) nedir?", o: ["Algoritma açığı değil; güç tüketimi, elektromanyetik yayılım veya zamanlama gibi fiziksel sızıntılar aracılığıyla bilgi çalma", "Güç kaynağını manipüle ederek veri bozma", "Fiziksel donanım erişimiyle şifre kırma", "Ağ trafiğini izleme yöntemi"], a: 0, e: "AES gibi matematiksel açıdan güvenli algoritmalar bile donanım uygulamasında güç analizine karşı savunmasız olabilir." },
      { q: "Türkiye'de STM (Savunma Teknolojileri Mühendisliği) hangi projelerle tanınmaktadır?", o: ["Kargu otonom silahlı insansız araç ve siber güvenlik çözümleri", "Uzay roketi geliştirme", "Ticari yazılım ürünleri", "Elektrikli araç bataryası"], a: 0, e: "Kargu kamikaze drone sistemi; otonomluğu ve yapay zeka entegrasyonu nedeniyle uluslararası etik tartışmalara yol açtı." },
      { q: "Kripto para cüzdanında 'seed phrase' (tohum ifadesi) neden kritiktir?", o: ["Cüzdanı sıfırdan yeniden oluşturmayı sağlayan geri dönüşü olmayan master anahtar", "Kripto para transfer şifresi", "İki faktörlü kimlik doğrulama kodu", "Borsa hesap kilidi açma kodu"], a: 0, e: "BIP-39 standardında 12-24 kelimeden oluşur; bu ifade çalınırsa tüm varlıklar geri alınamaz şekilde yitirilir." },
      { q: "Yazılım geliştirmede 'technical debt' (teknik borç) kavramı nedir?", o: ["Kısa vadeli çözümler için uzun vadede fazladan çalışma gerektiren kod kalitesi kurbanı", "Proje bütçe aşımı", "Eski sistemlere yapılan yatırım maliyeti", "Lisans ücretleri birikimi"], a: 0, e: "Ward Cunningham'ın metaforu; aşırı teknik borç sistemleri sürdürulemez hale getirir. Yeniden yazma kararları çoğu zaman birikmis borçtan kaynaklanır." },
      { q: "MapReduce programlama modeli nedir ve neden önemlidir?", o: ["Büyük veri setlerini paralel işlemek için map (dağıt) ve reduce (topla) adımlarına bölen Google'ın paradigması", "SQL sorguları optimize eden model", "Makine öğrenmesi eğitim çerçevesi", "Dağıtık önbellek yönetim modeli"], a: 0, e: "2004'te Google'ın tanımladığı bu model Hadoop'un temelini oluşturdu; petabyte ölçekli veri işlemenin kapısını açtı." },
      { q: "Kuantum üstünlüğü (quantum supremacy/advantage) hangi anlama gelir?", o: ["Kuantum bilgisayarın klasik bilgisayarların pratik sürede çözemeyeceği bir hesabı tamamlaması", "Kuantum bilgisayarların her alanda üstün olması", "Kuantum şifrelemenin kırılamaması", "Kuantum devrelerinin silikondan üstün olması"], a: 0, e: "Google'ın Sycamore çipi 2019'da 53 qubitli bir hesabı 200 saniyede yaptı; klasik süperbilgisayar için 10.000 yıl tahmin edildi." },
      { q: "LLM (Büyük Dil Modeli) bağlamında 'hallucination' (halüsinasyon) neden oluşur?", o: ["Model istatistiksel olarak tutarlı ama gerçekte yanlış metin üretir; doğruluk yerine akıcılığı optimize eder", "Yeterli eğitim verisi olmadığı için", "İnternet erişiminin kesilmesiyle", "Tokenizasyon hatalarından"], a: 0, e: "Modeller next-token tahminini optimize eder; bu nedenle 'doğru' değil 'doğruymuş gibi görünen' yanıt verir. RLHF ve RAG bu sorunu azaltır." },
      { q: "Türkiye'nin ilk yerli elektrikli otomobil markası hangisidir?", o: ["TOGG (Türkiye'nin Otomobili Girişim Grubu)", "Temsa", "Karsan", "Anadol"], a: 0, e: "TOGG 2023'te T10X modeliyle üretime başladı; beş Türk sanayi kuruluşunun ortaklığıyla kuruldu." },
      { q: "Post-kuantum kriptografi neden geliştirilmektedir?", o: ["Kuantum bilgisayarların RSA ve ECC gibi mevcut şifreleme sistemlerini kırabilecek olması", "Klasik bilgisayarların artık yetersiz kalması", "Kuantum iletişim ağları için şifreleme standardı", "Blockchain güvenliğini güçlendirmek için"], a: 0, e: "NIST 2022'de CRYSTALS-Kyber ve CRYSTALS-Dilithium'u standartlaştırdı; 'harvest now, decrypt later' saldırısına karşı acil geçiş gerekiyor." },
      { q: "FPGA (Field Programmable Gate Array) ile ASIC arasındaki temel fark nedir?", o: ["FPGA üretim sonrası yeniden programlanabilir; ASIC sabit devre belirli görev için optimize edilmiş", "FPGA daha hızlıdır her durumda", "ASIC yazılımla programlanır", "İkisi de GPU türüdür"], a: 0, e: "Bitcoin madenciliği başta FPGA ile yapıldı; sonra özel ASIC madenci çiplerine geçildi. FPGA prototipler ve özel işleme için hâlâ tercih ediliyor." },
      { q: "Türkiye'nin uzay ajansı TUA hangi hedefi 2030 için belirlemiştir?", o: ["Ay'a yerli uzay aracı indirimi", "Uydu üretim ve fırlatma", "Uluslararası Uzay İstasyonu'na katılım", "Mars keşif görevi"], a: 0, e: "Türkiye'nin Uzay Ajansı 2021'de 'Ulusal Uzay Programı'nı açıkladı; 2023'te Türkiye'nin ilk Ay misyonu için anlaşma imzalandı." },
      { q: "Dağıtık sistemlerde 'consensus algoritması' ne sağlar?", o: ["Birbirine güvenmeyen düğümlerin ortak bir duruma anlaşmasını garanti eder", "Ağ trafiğini dengeler", "Veri tabanı replikasyonunu senkronize eder", "Güvenlik duvarı kurallarını günceller"], a: 0, e: "Paxos ve Raft en bilinen consensus algoritmaları; blockchain'de Bitcoin'in Proof of Work ve Ethereum'un Proof of Stake bu amaca hizmet eder." }
