      { q: "Hangi Türk romancı 2006 Nobel Edebiyat Ödülü'nü kazanmıştır?", o: ["Orhan Pamuk", "Yaşar Kemal", "Adalet Ağaoğlu", "Latife Tekin"], a: 0, e: "Pamuk 'Kar', 'Benim Adım Kırmızı' ve 'İstanbul' ile Nobel jürisini etkiledi." },
      { q: "Dünya edebiyatında 'Savaşın edebiyatı'nın en ünlü örnekleri arasında Erich Maria Remarque'ın hangi eseri öne çıkar?", o: ["Batı Cephesinde Yeni Bir Şey Yok (1929)", "Üç Yoldaş", "Zafer Takı", "Gece Sığınağı"], a: 0, e: "Birinci Dünya Savaşı'nın trajedisini bir Alman askerin gözünden anlatan bu roman yüz binlerce sattı." },
      { q: "Türk edebiyatında 'Tanpınar'ın Huzur romanı' hangi şehri ve dönemi merkeze alır?", o: ["İstanbul ve 1930'lar Cumhuriyet dönemi", "Ankara ve 1950'ler", "Anadolu ve Kurtuluş Savaşı", "Paris ve 1920'ler"], a: 0, e: "Huzur Doğu-Batı gerilimi içinde kimlik arayışını İstanbul'un ruhuyla iç içe sunar." },
      { q: "Hangi Türk yazar 'Mavi Anadolu' hareketinin öncüsüdür?", o: ["Cevat Şakir Kabaağaçlı (Halikarnas Balıkçısı)", "Yaşar Kemal", "Kemal Tahir", "Sabahattin Ali"], a: 0, e: "Halikarnas Balıkçısı Ege kıyıları ve denizcileri anlatan eserleriyle Mavi Anadolu'nun kültürel kimliğini şekillendirdi." },
      { q: "Faulkner'ın 'Uğultulu Tepeler' ile hangisi karıştırılır ve ikisi arasındaki fark nedir?", o: ["Uğultulu Tepeler Emily Brontë'nin, Faulkner'ınki Ses ve Öfke'dir", "Her ikisi de Faulkner'ındır", "İkisi aynı romandır", "İkisi de Brontë'nin eseridir"], a: 0, e: "Uğultulu Tepeler (Wuthering Heights) Emily Brontë'nin 1847 eseri; Faulkner'ın başyapıtı ise Ses ve Öfke'dir (1929)." },
      { q: "Türk edebiyatında 'Sabahattin Ali' hangi eserle öne çıkmıştır?", o: ["Kürk Mantolu Madonna", "Yaban", "İnce Memed", "Kiralık Konak"], a: 0, e: "1943'te yayımlanan Kürk Mantolu Madonna, Türkiye'de son yıllarda en çok satılan klasik roman statüsüne geldi." },
      { q: "Hangi Fransız romancı doğalcılık (natüralizm) akımının kurucusu sayılır?", o: ["Émile Zola", "Gustave Flaubert", "Victor Hugo", "Honoré de Balzac"], a: 0, e: "Zola 'Rougon-Macquart' dizisinde bir ailenin birkaç kuşağını bilimsel determinizm anlayışıyla irdeledi." },
      { q: "Türk edebiyatında 'Zülfü Livaneli' hangi alanda çok yönlü bir sanatçı olarak öne çıkmıştır?", o: ["Hem romancı hem müzisyen", "Yalnızca şair", "Yalnızca tiyatro yazarı", "Yalnızca romancı"], a: 0, e: "Serenad, Engereğin Gözündeki Kamaşma gibi romanları ve söylediği şarkılarla Türk kültür hayatında çift kimliklidir." },
      { q: "Edebiyatta 'gotik roman' türünün ilk örneği hangi eserdir?", o: ["Otranto Şatosu (Horace Walpole, 1764)", "Frankenstein (Shelley, 1818)", "Dracula (Stoker, 1897)", "Doğu Masalları (1001 Gece)"], a: 0, e: "Walpole'un 1764 eseri ortaçağ şatosu, gizemli olaylar ve aşırı duygu öğeleriyle gotik roman türünü başlattı." },
      { q: "Türk edebiyatında 'Cumhuriyet dönemi çocuk edebiyatı'nın en tanınan yazarı kimdir?", o: ["Kemalettin Tuğcu", "Sait Faik", "Orhan Kemal", "Nazım Hikmet"], a: 0, e: "Kemalettin Tuğcu duygusal ve ahlaki içerikli çocuk romanlarıyla Türkiye'nin en çok satılan çocuk yazarı oldu." },
      { q: "Kafka'nın 'Dava' (Der Process) romanının kahramanı Josef K. neden yargılanır?", o: ["Suçu hiçbir zaman açıklanmaz — bu belirsizlik romanın özüdür", "Cinayet suçuyla", "Hırsızlık suçuyla", "Devlet karşıtı faaliyetlerle"], a: 0, e: "Bürokratik sistemin anlamsızlığını ve suçluluk psikolojisini inceleyen bu roman Kafka'nın ölümünden sonra yayımlandı." },
      { q: "Türk edebiyatında 'Necip Fazıl Kısakürek' hangi eserle tanınır?", o: ["Çile (şiir) ve Büyük Doğu (dergi)", "İnce Memed", "Tutunamayanlar", "Serenad"], a: 0, e: "Çile Türk şiirinin en çok okunan şiir kitaplarından biri; Büyük Doğu dergisi 1943'ten itibaren önemli bir kültür platformu oldu." },
      { q: "Gabriel García Márquez Nobel ödülünü hangi eserle kazandı?", o: ["Yüzyıllık Yalnızlık (1982 Nobel)", "Aşk ve Öbür Şeytan", "Kolera Günlerinde Aşk", "Kötü Saatte"], a: 1, e: "Nobel jürisi 1982'de García Márquez'e ödülü Latin Amerika edebiyatının tamamı ve özellikle Yüzyıllık Yalnızlık için verdi." },
      { q: "Türk edebiyatında 'Ahmed Arif' hangi eseriyle öne çıkmıştır?", o: ["Hasretinden Prangalar Eskittim", "Çile", "Kuvâyi Milliye", "Saatleri Ayarlama Enstitüsü"], a: 0, e: "1968'de yayımlanan bu tek şiir kitabı Türk edebiyatının en çok okunan şiir derlemelerinden biri haline geldi." },
      { q: "Dünya edebiyatında 'distopya' türünün iki klasiği hangilerdir?", o: ["1984 (Orwell) ve Cesur Yeni Dünya (Huxley)", "Hayvan Çiftliği ve Sinek Tanrısı", "Fahrenheit 451 ve Biz", "Handmaid'in Öyküsü ve Atlas Silkindi"], a: 0, e: "Her iki eser de totalitarizme karşı birer uyarıdır; Orwell siyasi baskıyı, Huxley biyolojik tüketimciliği işler." },
      { q: "Türk edebiyatında 'Haldun Taner' hangi türün öncüsüdür?", o: ["Kabare tiyatrosu ve kısa öykü", "Uzun roman", "Şiir", "Deneme"], a: 0, e: "Keşanlı Ali Destanı ile Türk tiyatrosunda epik ve kabare türünü yerleştirdi; kısa hikayeleriyle de kalıcı iz bıraktı." },
      { q: "İngiliz edebiyatında 'Romantik kuşak' şairleri kimlerdir?", o: ["Blake, Wordsworth, Coleridge, Byron, Shelley, Keats", "Pope, Dryden, Swift", "Donne, Herbert, Marvell", "Chaucer, Spenser, Sidney"], a: 0, e: "Bu altı şair 1780-1850 arasında yazan Romantikleri temsil eder; doğa, bireysellik ve hayal gücünü merkeze alırlar." },
      { q: "Türk edebiyatında 'Tomris Uyar' hangi türde öne çıkmıştır?", o: ["Kısa hikaye ve çeviri", "Şiir ve roman", "Tiyatro ve eleştiri", "Deneme ve biyografi"], a: 0, e: "Türk öykücülüğünün ustası Tomris Uyar aynı zamanda dünya edebiyatından önemli eserleri Türkçeye kazandırmıştır." },
      { q: "Rus edebiyatının 'altın çağı' hangi dönemi kapsar?", o: ["19. yüzyıl (Puşkin'den Çehov'a)", "18. yüzyıl", "20. yüzyıl başı", "17. yüzyıl"], a: 0, e: "Puşkin, Gogol, Turgenev, Dostoyevski, Tolstoy ve Çehov bu altın çağın başyapıtlarını yarattı." },
      { q: "Türk edebiyatında 'Cumhuriyet dönemi' epik şiirinin en önemli eseri hangisidir?", o: ["Nazım Hikmet'in 'Memleketimden İnsan Manzaraları'", "Yahya Kemal'in 'Aziz İstanbul'u", "Necip Fazıl'ın 'Çile'si", "Faruk Nafiz'in 'Han Duvarları'"], a: 0, e: "1938-1966 yılları arasında yazılan bu epik eser 8.000 dizeden oluşur; Türkiye'nin toplumsal panoramasını sunar." },
      { q: "Hangi Nobel Edebiyat Ödüllü yazar 'Sineklerin Tanrısı' ile tanınır?", o: ["William Golding (1983)", "John Steinbeck", "Samuel Beckett", "Harold Pinter"], a: 0, e: "1954'te yayımlanan bu roman ıssız bir adaya düşen çocukların uygarlık maskesini nasıl düşürdüğünü anlatır." },
      { q: "Türk edebiyatında 'Orhan Veli Kanık' hangi şiiriyle en çok tanınır?", o: ["Kitabe-i Seng-i Mezar ve Anlatamıyorum", "Çile", "Kuvâyi Milliye", "İstanbul'u Dinliyorum"], a: 1, e: "Orhan Veli Garip hareketi öncüsüdür; ölümünden sonra bulunan 'Anlatamıyorum' şiiri Türk şiirinin ikonlaşmış parçalarındandır." },
      { q: "Hangi Fransız yazar 'Bulantı' (La Nausée) ve 'Varlık ve Hiçlik' gibi eserlerle varoluşçuluğu geliştirdi?", o: ["Jean-Paul Sartre", "Albert Camus", "Simone de Beauvoir", "Michel Foucault"], a: 0, e: "Sartre 1964 Nobel ödülünü reddeden tek kişidir; felsefe, tiyatro ve roman türlerinde varoluşçuluğun sesini duyurdu." },
      { q: "Türk edebiyatında 'Cahit Sıtkı Tarancı' hangi şiiriyle ölümsüzleşmiştir?", o: ["Otuz Beş Yaş", "Sonbahar", "Yağmur", "Gece"], a: 0, e: "'Yaşımın en güzel günleri yandı' dizesiyle başlayan Otuz Beş Yaş, ölüm karşısındaki varoluş sancısını dile getiren klasikleşmiş bir şiirdir." }
